task("faucet", "Sends ETH and tokens to an address")
  .addPositionalParam("receiver", "The address that will receive them")
  .setAction(async ({ receiver }, { ethers }) => {
    if (network.name === "hardhat") {
      console.warn(
        "You are running the faucet task with Hardhat network, which" +
          "gets automatically created and destroyed every time. Use the Hardhat" +
          " option '--network localhost'"
      );
    }

    const addressesFile =
      __dirname + "/../frontend/src/contracts/contract-address.json";

    if (!fs.existsSync(addressesFile)) {
      console.error("You need to deploy your contract first");
      return;
    }

    const addressJson = fs.readFileSync(addressesFile);
    const address = JSON.parse(addressJson);

    if ((await ethers.provider.getCode(address.Token)) === "0x") {
      console.error("You need to deploy your contract first");
      return;
    }

    const token = await ethers.getContractAt("Token", address.Token);
    const [sender] = await ethers.getSigners();

    const tx = await token.transfer(receiver, 100);
    await tx.wait();

    const tx2 = await sender.sendTransaction({
      to: receiver,
      value: ethers.constants.WeiPerEther,
    });
    await tx2.wait();

    console.log(`Transferred 1 ETH and 100 tokens to ${receiver}`);
  });

import { IgnitionError } from "../errors";

import { DeploymentLoader } from "./deployment-loader/types";
import { ERRORS } from "./errors-list";
import {
  applyNewMessage,
  loadDeploymentState,
} from "./execution/deployment-state-helpers";
import {
  JournalMessageType,
  WipeExecutionStateMessage,
} from "./execution/types/messages";

export class Wiper {
  constructor(private _deploymentLoader: DeploymentLoader) {}

  public async wipe(futureId: string) {
    const deploymentState = await loadDeploymentState(this._deploymentLoader);

    if (deploymentState === undefined) {
      throw new IgnitionError(ERRORS.WIPE.UNINITIALIZED_DEPLOYMENT, {
        futureId,
      });
    }

    const executionState = deploymentState.executionStates[futureId];

    if (executionState === undefined) {
      throw new IgnitionError(ERRORS.WIPE.NO_STATE_FOR_FUTURE, { futureId });
    }

    const dependents = Object.values(deploymentState.executionStates).filter(
      (psm) => psm.dependencies.has(futureId)
    );

    if (dependents.length > 0) {
      throw new IgnitionError(ERRORS.WIPE.DEPENDENT_FUTURES, {
        futureId,
        dependents: dependents.map((d) => d.id).join(", "),
      });
    }

    const wipeMessage: WipeExecutionStateMessage = {
      type: JournalMessageType.WIPE_APPLY,
      futureId,
    };

    return applyNewMessage(
      wipeMessage,
      deploymentState,
      this._deploymentLoader
    );
  }
}

import { window, ExtensionContext, commands, Uri } from "vscode";

const SURVEY_URL = "https://solidity.survey-research.net/solidity-survey";
const SURVEY_COMPLETED_KEY = "soliditySurvey2026Completed";
const SURVEY_LAST_SEEN_KEY = "soliditySurvey2026LastSeen";

// Show the survey popup if the user hasn't seen it in the last 7 days
const SURVEY_COOLDOWN_PERIOD = 7 * 24 * 60 * 60 * 1000;
const SURVEY_END_DATE = Date.parse("2026-03-18 23:59:00 +0000");
const SURVEY_TEXT = "Please take a few minutes to complete the Solidity Survey";
const SURVEY_CTA = "Complete";

export async function showSoliditySurveyPopup({
  context,
}: {
  context: ExtensionContext;
}): Promise<void> {
  const now = new Date().getTime();

  if (now > SURVEY_END_DATE) {
    return;
  }

  const completed = context.globalState.get<boolean>(SURVEY_COMPLETED_KEY);

  if (completed === true) {
    return;
  }

  const lastSeen = context.globalState.get<number>(SURVEY_LAST_SEEN_KEY);

  if (lastSeen !== undefined && now < lastSeen + SURVEY_COOLDOWN_PERIOD) {
    return;
  }

  const item = await window.showInformationMessage(SURVEY_TEXT, SURVEY_CTA);

  await context.globalState.update(SURVEY_LAST_SEEN_KEY, now);

  if (item === SURVEY_CTA) {
    await commands.executeCommand("vscode.open", Uri.parse(SURVEY_URL));

    await context.globalState.update(SURVEY_COMPLETED_KEY, true);
  }
}

import * as parser from "@solidity-parser/parser";
import * as matcher from "@analyzer/matcher";
import {
  Node,
  SourceUnitNode,
  SolFileIndexMap,
  ISolFileEntry,
  SolFileState,
} from "@common/types";

export async function analyzeSolFile(
  { solFileIndex }: { solFileIndex: SolFileIndexMap },
  solFileEntry: ISolFileEntry,
  newText?: string
): Promise<Node | undefined> {
  try {
    solFileEntry.orphanNodes = [];

    if (newText !== undefined) {
      solFileEntry.text = newText;
    }

    try {
      solFileEntry.ast = parser.parse(solFileEntry.text ?? "", {
        loc: true,
        range: true,
        tolerant: true,
      });
    } catch {
      solFileEntry.status = SolFileState.ERRORED;
      return solFileEntry.analyzerTree.tree;
    }

    if (solFileEntry.isAnalyzed()) {
      const oldDocumentsAnalyzerTree = solFileEntry.analyzerTree
        .tree as SourceUnitNode;

      for (const importNode of oldDocumentsAnalyzerTree.getImportNodes()) {
        importNode.getParent()?.removeChild(importNode);
        importNode.setParent(undefined);
      }
    }

    solFileEntry.status = SolFileState.ANALYZED;
    const node = await matcher.find(
      solFileEntry.ast,
      solFileEntry.uri,
      solFileEntry.project.basePath,
      solFileIndex
    );
    solFileEntry.analyzerTree.tree = await node.accept(
      matcher.find,
      solFileEntry.orphanNodes
    );

    return solFileEntry.analyzerTree.tree;
  } catch {
    return solFileEntry.analyzerTree.tree;
  }
}

import 'dotenv/config';
export function node_url(networkName: string): string {
  if (networkName) {
    const uri = process.env['ETH_NODE_URI_' + networkName.toUpperCase()];
    if (uri && uri !== '') {
      return uri;
    }
  }

  let uri = process.env.ETH_NODE_URI;
  if (uri) {
    uri = uri.replace('{{networkName}}', networkName);
  }
  if (!uri || uri === '') {
    if (networkName === 'localhost') {
      return 'http://localhost:8545';
    }
    // throw new Error(`environment variable "ETH_NODE_URI" not configured `);
    return '';
  }
  if (uri.indexOf('{{') >= 0) {
    throw new Error(
      `invalid uri or network not supported by nod eprovider : ${uri}`
    );
  }
  return uri;
}

export function getMnemonic(networkName?: string): string {
  if (networkName) {
    const mnemonic = process.env['MNEMONIC_' + networkName.toUpperCase()];
    if (mnemonic && mnemonic !== '') {
      return mnemonic;
    }
  }

  const mnemonic = process.env.MNEMONIC;
  if (!mnemonic || mnemonic === '') {
    return 'test test test test test test test test test test test junk';
  }
  return mnemonic;
}

export function accounts(networkName?: string): {mnemonic: string} {
  return {mnemonic: getMnemonic(networkName)};
}

import type { Artifact, BuildInfo } from "@nomicfoundation/ignition-core";

import path from "node:path";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import {
  exists,
  readdir,
  readJsonFile,
} from "@nomicfoundation/hardhat-utils/fs";

export async function verifyArtifactsVersion(
  deploymentDir: string | undefined,
): Promise<void> {
  const artifactsDir = `${deploymentDir}/artifacts`;

  if (deploymentDir === undefined || !(await exists(artifactsDir))) {
    return;
  }

  for (const filename of await readdir(artifactsDir)) {
    if (filename.endsWith(".dbg.json")) {
      continue;
    }

    const artifactPath = path.join(artifactsDir, filename);
    const artifact: Artifact = await readJsonFile(artifactPath);

    if (artifact._format === "hh-sol-artifact-1") {
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.GENERAL.ARTIFACT_MIGRATION_NEEDED,
        {
          deploymentId: deploymentDir.split(path.sep).pop(),
        },
      );
    }
  }

  const buildInfoDir = `${deploymentDir}/build-info`;

  if (!(await exists(buildInfoDir))) {
    return;
  }

  for (const filename of await readdir(buildInfoDir)) {
    const buildInfoPath = path.join(buildInfoDir, filename);
    const buildInfo: BuildInfo = await readJsonFile(buildInfoPath);

    if (buildInfo._format === "hh-sol-build-info-1") {
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.GENERAL.ARTIFACT_MIGRATION_NEEDED,
        {
          deploymentId: deploymentDir.split(path.sep).pop(),
        },
      );
    }
  }
}

import type { SerializedIgnitionModule } from "@nomicfoundation/ignition-core";

import { createRequire } from "node:module";
import path from "node:path";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import {
  ensureDir,
  exists,
  readUtf8File,
  writeUtf8File,
} from "@nomicfoundation/hardhat-utils/fs";

export async function writeVisualization(
  visualizationPayload: {
    module: SerializedIgnitionModule;
    batches: string[][];
  },
  { cacheDir }: { cacheDir: string },
): Promise<void> {
  const require = createRequire(import.meta.url);
  const templateDir = path.join(
    require.resolve("@nomicfoundation/ignition-ui/package.json"),
    "../dist",
  );

  const templateDirExists = await exists(templateDir);

  if (!templateDirExists) {
    throw new HardhatError(
      HardhatError.ERRORS.IGNITION.INTERNAL.VISUALIZATION_TEMPLATE_DIR_NOT_FOUND,
      {
        templateDir,
      },
    );
  }

  const visualizationDir = path.join(cacheDir, "visualization");

  await ensureDir(visualizationDir);

  const indexHtml = await readUtf8File(path.join(templateDir, "index.html"));
  const updatedHtml = indexHtml
    .toString()
    .replace('{ "unloaded": true }', JSON.stringify(visualizationPayload));

  await writeUtf8File(path.join(visualizationDir, "index.html"), updatedHtml);
}

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import {
  isAddress,
  isValidChecksumAddress,
} from "@nomicfoundation/hardhat-utils/eth";

export function assertHexString(hexString: string): void {
  if (typeof hexString !== "string" || !/^0x[0-9a-fA-F]*$/.test(hexString)) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_HEX_STRING,
      {
        value: hexString,
      },
    );
  }
}

export function assertTxHash(hexString: string): void {
  assertHexString(hexString);

  if (hexString.length !== 66) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_TX_HASH,
      {
        value: hexString,
      },
    );
  }
}

export async function assertValidAddress(address: string): Promise<void> {
  if (!isAddress(address)) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_ADDRESS,
      {
        value: address,
      },
    );
  }

  const hasChecksum = address !== address.toLowerCase();

  if (hasChecksum && !(await isValidChecksumAddress(address))) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_CHECKSUM_ADDRESS,
      {
        value: address,
      },
    );
  }
}

export function assertLargerThan(a: bigint, b: bigint): void;
export function assertLargerThan(a: number, b: number): void;
export function assertLargerThan(a: number | bigint, b: number | bigint): void {
  if (a <= b) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.BLOCK_NUMBER_SMALLER_THAN_CURRENT,
      {
        newValue: a,
        currentValue: b,
      },
    );
  }
}

import type { NumberLike } from "../types.js";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import { toBigInt as toBigIntUtil } from "@nomicfoundation/hardhat-utils/bigint";

export function toNumber(x: NumberLike): number {
  return Number(toRpcQuantity(x));
}

export async function toBigInt(x: NumberLike): Promise<bigint> {
  return toBigIntUtil(toRpcQuantity(x));
}

export function toRpcQuantity(x: NumberLike): string {
  let hex: string;

  if (typeof x === "number" || typeof x === "bigint") {
    if (x < 0) {
      throw new HardhatError(
        HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.CANNOT_CONVERT_NEGATIVE_NUMBER_TO_RPC_QUANTITY,
        {
          value: x,
        },
      );
    }

    hex = `0x${x.toString(16)}`;
  } else if (typeof x === "string") {
    if (!x.startsWith("0x")) {
      throw new HardhatError(
        HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.ONLY_ALLOW_0X_PREFIXED_STRINGS,
      );
    }
    hex = x;
  } else {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.CANNOT_CONVERT_TO_RPC_QUANTITY,
      {
        value: x,
      },
    );
  }

  if (hex === "0x0") {
    return hex;
  }

  return hex.startsWith("0x") ? hex.replace(/0x0+/, "0x") : `0x${hex}`;
}

import assert from "node:assert/strict";

import { ensureError } from "@nomicfoundation/hardhat-utils/error";
import { deepEqual } from "@nomicfoundation/hardhat-utils/lang";

// EIP-55 addresses are 0x-prefixed 40 hex chars; case carries only checksum info.
const ADDRESS_REGEX = /^0x[0-9a-fA-F]{40}$/;

function isAddressLike(value: unknown): value is string {
  return typeof value === "string" && ADDRESS_REGEX.test(value);
}

export function anyValue() {
  return true;
}

export async function isArgumentMatch(
  actualArgs: any[],
  expectedArgs: any[],
): Promise<boolean> {
  assert.ok(
    actualArgs.length === expectedArgs.length,
    `${actualArgs.length} arguments emitted, but ${expectedArgs.length} expected`,
  );

  for (let index = 0; index < actualArgs.length; index++) {
    const emittedArg = actualArgs[index];
    const expectedArg = expectedArgs[index];

    if (typeof expectedArg === "function") {
      try {
        if (expectedArg(emittedArg) !== true) {
          return false;
        }
      } catch (e) {
        ensureError(e);
        assert.fail(
          `The predicate of index ${index} threw when called: ${e.message}`,
        );
      }
    } else if (isAddressLike(emittedArg) && isAddressLike(expectedArg)) {
      if (emittedArg === expectedArg) {
        continue;
      }

      if (emittedArg.toLowerCase() !== expectedArg.toLowerCase()) {
        return false;
      }
    } else {
      if (!(await deepEqual(emittedArg, expectedArg))) {
        return false;
      }
    }
  }

  return true;
}

import { ChildProcess, spawn } from "child_process";

import { getPrefixedCommand, normalizeVenvPath } from "../utils/venv";
import { ExternalServer } from "./external-server";

export class VenvDevnet extends ExternalServer {
    private command: string;
    private args?: string[];
    private vmLang?: string;

    constructor(
        venvPath: string,
        host: string,
        port: string,
        args?: string[],
        stdout?: string,
        stderr?: string,
        vmLang?: string
    ) {
        super(host, port, "is_alive", "integrated-devnet", stdout, stderr);

        this.command = "starknet-devnet";
        this.args = args;
        this.vmLang = vmLang;

        if (venvPath !== "active") {
            this.command = getPrefixedCommand(normalizeVenvPath(venvPath), this.command);
        }
    }

    protected async spawnChildProcess(): Promise<ChildProcess> {
        const args = ["--host", this.host, "--port", this.port].concat(this.args || []);
        const options = { env: { PATH: process.env.PATH, STARKNET_DEVNET_CAIRO_VM: this.vmLang } };
        return spawn(this.command, args, options);
    }

    protected cleanup(): void {
        this.childProcess?.kill();
    }
}

import { Bar, Options, Preset, Presets, ValueType } from "cli-progress";

import { BYTES_IN_MB } from "../constants";

export class BaseProgressBarProcessor {
  private _progressBar: Bar | null = null;

  public createAndStartProgressBar(
    barOptions: Options,
    totalValue: number,
    startValue: number,
    barPreset: Preset = Presets.shades_classic,
  ) {
    if (this._progressBar) return;

    this._progressBar = new Bar(barOptions, barPreset);
    this._progressBar.start(totalValue, startValue);
  }

  public updateProgressBar(addedChunk: number) {
    if (!this._progressBar) return;

    this._progressBar.increment(addedChunk);
  }

  public stopProgressBar() {
    if (!this._progressBar) return;

    this._progressBar.stop();
    this._progressBar = null;
  }

  public formatToMB(v: number, options: Options, type: ValueType): string {
    const toMb = (value: number): string => {
      return (value / BYTES_IN_MB).toFixed(2);
    };

    switch (type) {
      case "percentage":
        return options.autopaddingChar ? (options.autopaddingChar + v).slice(-3) : v.toString();
      case "total":
        return toMb(v);
      case "value":
        return toMb(v);
      default:
        return v.toString();
    }
  }
}

export let ProgressBarProcessor: BaseProgressBarProcessor | null = null;

export function createProgressBarProcessor() {
