import { UiFuture, UiFutureStatusType, UiState } from "../types";

export function calculateBatchDisplay(state: UiState): {
  text: string;
  height: number;
} {
  const batch = state.batches[state.currentBatch - 1];
  const height = batch.length + (state.ledgerMessageIsDisplayed ? 4 : 2);

  let text = `Batch #${state.currentBatch}\n`;

  text += batch
    .sort((a, b) => a.futureId.localeCompare(b.futureId))
    .map((v) => _futureStatus(v, state.gasBumps, state.maxFeeBumps))
    .join("\n");

  text += "\n";

  if (state.ledger) {
    text += `\n  Ledger: ${state.ledgerMessage}\n`;
  }

  return { text, height };
}

function _futureStatus(
  future: UiFuture,
  gasBumps: Record<string, number>,
  maxFeeBumps: number
): string {
  switch (future.status.type) {
    case UiFutureStatusType.UNSTARTED: {
      const gas = gasBumps[future.futureId];
      return `  Executing ${future.futureId}${
        gas !== undefined
          ? ` - bumping gas fee (${gas}/${maxFeeBumps})...`
          : "..."
      }`;
    }
    case UiFutureStatusType.SUCCESS: {
      return `  Executed ${future.futureId}`;
    }
    case UiFutureStatusType.TIMEDOUT: {
      return `  Timed out ${future.futureId}`;
    }
    case UiFutureStatusType.ERRORED: {
      return `  Failed ${future.futureId}`;
    }
    case UiFutureStatusType.HELD: {
      return `  Held ${future.futureId}`;
    }
  }
}

import * as versions from 'compare-versions';

import { ValidationRunData } from './run';

type ValidationDataV1 = ValidationRunData;

type ValidationDataV2 = ValidationRunData[];

const currentMajor = '3';
const currentVersion = '3.4';

interface ValidationDataV3 {
  version: '3' | '3.1' | '3.2' | '3.3' | '3.4';
  log: ValidationRunData[];
}

export type ValidationDataCurrent = ValidationDataV3;

export type ValidationData = ValidationDataV1 | ValidationDataV2 | ValidationDataV3;

export function normalizeValidationData(data: ValidationData): ValidationDataCurrent {
  if (isCurrentValidationData(data, false)) {
    return data;
  } else if (Array.isArray(data)) {
    return { version: currentVersion, log: data };
  } else {
    return { version: currentVersion, log: [data] };
  }
}

export function isCurrentValidationData(data: ValidationData, exact = true): data is ValidationDataCurrent {
  if (Array.isArray(data)) {
    return false;
  } else if (!('version' in data)) {
    return false;
  } else if (typeof data.version === 'string' && versions.validate(data.version)) {
    if (exact) {
      return data.version === currentVersion;
    } else {
      return versions.compare(data.version, `${currentMajor}.*`, '=');
    }
  } else {
    throw new Error('Unknown version or malformed validation data');
  }
}

export function concatRunData(
  newRunData: ValidationRunData,
  previousData?: ValidationDataCurrent,
): ValidationDataCurrent {
  return {
    version: currentVersion,
    log: [newRunData].concat(previousData?.log ?? []),
  };
}

import fs from "fs-extra";
import path from "path";

import { I4BytesEntry } from "./types";

// To locally cache contract name, decimals, and ABI to prevent async API calls
export class TracerCache {
  public tokenDecimals: Map<string, number> = new Map();
  public contractNames: Map<string, string> = new Map();
  public fourByteDir: Map<string, I4BytesEntry[]> = new Map();

  public cachePath: string | undefined;

  public setCachePath(cachePath: string) {
    this.cachePath = cachePath;
  }

  public load() {
    fs.ensureFileSync(this.getTracerCachePath());
    let json;
    try {
      json = fs.readJSONSync(this.getTracerCachePath());
    } catch {
      json = {};
    }
    this.tokenDecimals = new Map(json.tokenDecimals ?? []);
    this.contractNames = new Map(json.contractNames ?? []);
    this.fourByteDir = new Map(json.fourByteDir ?? []);
  }

  public save() {
    fs.ensureFileSync(this.getTracerCachePath());

    fs.writeJSONSync(
      this.getTracerCachePath(),
      {
        tokenDecimals: Array.from(this.tokenDecimals.entries()),
        contractNames: Array.from(this.contractNames.entries()),
        fourByteDir: Array.from(this.fourByteDir.entries()),
      },
      { spaces: 2 }
    );
  }

  public getTracerCachePath() {
    if (!this.cachePath) {
      throw new Error("[hardhat-tracer]: cachePath not set");
    }
    return path.join(this.cachePath, "hardhat-tracer-cache", `data.json`);
  }
}

import { MinimalInterpreterStep } from "hardhat/internal/hardhat-network/provider/vm/types";

import { Item } from "../types";
import {
  memorySlice,
  parseBytes32,
  parseNumber,
  shallowCopyStack2,
} from "../utils";

import { LOG } from "./log";

export interface LOG3 extends LOG {
  topics: [string, string, string];
}

function parse(
  step: MinimalInterpreterStep,
  currentAddress?: { value: string }
): Item<LOG3> {
  if (!currentAddress) {
    throw new Error(
      "[hardhat-tracer]: currentAddress is required for log to be recorded"
    );
  }

  const stack = shallowCopyStack2(step.stack);
  if (stack.length < 5) {
    throw new Error("[hardhat-tracer]: Faulty LOG3");
  }

  const dataOffset = parseNumber(stack.pop()!);
  const dataSize = parseNumber(stack.pop()!);
  const topic0 = parseBytes32(stack.pop()!);
  const topic1 = parseBytes32(stack.pop()!);
  const topic2 = parseBytes32(stack.pop()!);

  const data = memorySlice(step.memory, dataOffset, dataSize);

  return {
    opcode: "LOG3",
    params: {
      data,
      topics: [topic0, topic1, topic2],
      address: currentAddress,
    },
    format(): string {
      throw new Error("[hardhat-tracer]: Not implemented directly");
    },
  };
}

export default { parse };

