import { HardhatError } from "@nomicfoundation/hardhat-errors";
import { deepClone, isObject } from "@nomicfoundation/hardhat-utils/lang";

const PRIMITIVE = [
  "bigint",
  "boolean",
  "function",
  "number",
  "string",
  "symbol",
];

export async function deepCopy<T = any>(value: T): Promise<T> {
  // The function 'deepClone' from 'hardhat-utils' cannot be used to replace this function, it won't properly clone
  // the value. The reason is that 'deepClone' doesn't handle certain custom cases,
  // such as skipping objects with a getAddress method and treating primitive types explicitly.
  // These custom checks are necessary for correct behavior in our use case.

  if (
    value === null ||
    value === undefined ||
    PRIMITIVE.includes(typeof value)
  ) {
    return value;
  }

  // Keep any Addressable
  if (
    isObject(value) &&
    "getAddress" in value &&
    typeof value.getAddress === "function"
  ) {
    return value;
  }

  if (Array.isArray(value)) {
    return await deepClone(value);
  }

  if (isObject(value)) {
    const newV: any = {};

    return Object.keys(value).reduce((accum, key) => {
      accum[key] = value[key];
      return accum;
    }, newV);
  }

  throw new HardhatError(
    HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.UNSUPPORTED_TYPE_FOR_DEEP_COPY,
    {
      value,
      type: typeof value,
    },
  );
}

import { readdir, readFile, appendFile } from "node:fs/promises";
import path from "node:path";
import process from "node:process";

import {
  parseFrontMatter,
  extractDocsUrlsFromFrontMatter,
} from "./lib/changesets.ts";

const changesetDir = ".changeset";

async function collectDocsUrls() {
  if (process.env.GITHUB_OUTPUT === undefined) {
    throw new Error("GITHUB_OUTPUT is not defined");
  }

  const files = (await readdir(changesetDir)).filter(
    (file) => file.endsWith(".md") && file !== "README.md",
  );

  const allUrls = new Set();

  for (const file of files) {
    const content = await readFile(path.join(changesetDir, file), "utf-8");
    const { frontMatter } = parseFrontMatter(content);
    const urls = extractDocsUrlsFromFrontMatter(frontMatter);
    for (const url of urls) {
      allUrls.add(url);
    }
  }

  const hasDocs = allUrls.size > 0;
  console.log(`has_docs: ${hasDocs}`);
  await appendFile(process.env.GITHUB_OUTPUT, `has_docs=${hasDocs}\n`);

  if (hasDocs) {
    const lines = ["## Documentation PRs to merge"];
    const sortedUrls = Array.from(allUrls).sort();
    for (const url of sortedUrls) {
      lines.push(`- ${url}`);
    }
    const commentBody = lines.join("\n");
    console.log(`comment_body:\n${commentBody}`);
    await appendFile(
      process.env.GITHUB_OUTPUT,
      `comment_body<<EOF\n${commentBody}\nEOF\n`,
    );
  }
}

await collectDocsUrls();
